-- Semantic metadata only: never persist operational records, snapshots, SQL, or staging payloads.
do $$ begin create extension if not exists vector; exception when undefined_file then raise notice 'pgvector unavailable; textual fallback remains enabled'; end $$;
create table public.agent_semantic_items (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid null references public.ai_agents(id) on delete cascade,item_type text not null check(item_type in ('tool','metric','dimension','indicator','example','alias','knowledge_hint','dashboard_hint','report_hint')),item_key text not null,title text not null,description text null,synonyms text[] not null default '{}',tool_key text null,tool_args_template jsonb not null default '{}'::jsonb,metadata jsonb not null default '{}'::jsonb,embedding jsonb null,embedding_model text null,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.agent_tool_memory (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid not null references public.ai_agents(id) on delete cascade,normalized_question text not null,question_hash text not null,tool_plan jsonb not null,tool_result_shape jsonb not null default '{}'::jsonb,success_count integer not null default 0,failure_count integer not null default 0,approved_by_user boolean not null default false,last_error text null,canonical_data_version text null,embedding jsonb null,embedding_model text null,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),last_used_at timestamptz null,unique(tenant_id,agent_id,question_hash));
create table public.agent_response_cache (id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id) on delete cascade,agent_id uuid not null references public.ai_agents(id) on delete cascade,normalized_question text not null,question_hash text not null,tool_plan_hash text not null,tool_result_hash text not null,canonical_data_version text not null,agent_config_hash text not null default 'legacy',knowledge_version text null,content text not null,output_json jsonb not null default '{}'::jsonb,expires_at timestamptz null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index on public.agent_semantic_items(tenant_id,agent_id,is_active); create index on public.agent_tool_memory(tenant_id,agent_id,question_hash); create index on public.agent_response_cache(tenant_id,agent_id,question_hash,canonical_data_version);
alter table public.agent_semantic_items enable row level security; alter table public.agent_tool_memory enable row level security; alter table public.agent_response_cache enable row level security;
create policy "tenant members semantic" on public.agent_semantic_items for all to authenticated using (public.is_member_of_tenant(tenant_id)) with check (public.is_member_of_tenant(tenant_id)); create policy "tenant members tool memory" on public.agent_tool_memory for all to authenticated using (public.is_member_of_tenant(tenant_id)) with check (public.is_member_of_tenant(tenant_id)); create policy "tenant members response cache" on public.agent_response_cache for all to authenticated using (public.is_member_of_tenant(tenant_id)) with check (public.is_member_of_tenant(tenant_id));
